// Parse incoming SMS from Twilio
const body = $json["body"] || {};

const smsData = {
  messageSid: body.MessageSid || '',
  from: body.From || '', // Customer phone number
  to: body.To || '', // Your Twilio number
  body: body.Body || '',
  numMedia: parseInt(body.NumMedia) || 0,
  accountSid: body.AccountSid || '',
  receivedAt: new Date().toISOString()
};

return [{ json: smsData }];

// Determine if customer exists and handle accordingly
const customers = $json;
const fromNumber = $json["from"];
const messageBody = ($json["body"] || '').toLowerCase().trim();

if (customers.length === 0) {
  // New lead from SMS
  return [{ json: {
    action: 'new_lead_from_sms',
    phoneNumber: fromNumber,
    message: messageBody,
    needsFollowUp: true,
    suggestedResponse: 'Thanks for your message! A real estate agent will contact you shortly.'
  } }];
}

const customer = customers[0];

// Handle special commands
if (messageBody.includes('stop') || messageBody.includes('unsubscribe')) {
  return [{ json: {
    action: 'opt_out_request',
    customerId: customer.id,
    phoneNumber: fromNumber,
    message: messageBody
  } }];
}

if (messageBody.includes('help') || messageBody.includes('info')) {
  return [{ json: {
    action: 'info_request',
    customerId: customer.id,
    phoneNumber: fromNumber,
    message: messageBody,
    suggestedResponse: 'Visit our website or call us for property listings and agent assistance.'
  } }];
}

// For general messages, log and optionally trigger AI response
return [{ json: {
  action: 'customer_sms_received',
  customerId: customer.id,
  customerName: `${customer.first_name} ${customer.last_name}`,
  phoneNumber: fromNumber,
  message: messageBody,
  needsResponse: true,
  originalMessageSid: $json["messageSid"]
} }];

