  'new_lead_from_sms': 'Thanks for your message! A real estate agent will contact you shortly.',
  'info_request': 'Visit our website or call us for property listings and agent assistance.',
  'default': 'Thank you for contacting us. We\'ll get back to you soon.'
};

let responseMessage = responses[$json["action"]] || responses['default'];

return [{ json: {
  action: 'send_sms_response',
  to: $json["phoneNumber"],
  message: responseMessage,
  messageSid: 'simulated_' + Date.now(),
  sentAt: new Date().toISOString()
} }];
